def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
  val n = online.length
  if (n == 0) return -1L

  val allCosts = edges.map(edge => edge(2)).toList
  val maxCost = if (allCosts.isEmpty) 0 else allCosts.max

  var low = 0L
  var high = maxCost
  var answer = -1L

  while (low <= high) {
    val mid = (low + high) / 2
    if (isPossible(edges, online, mid, k, n)) {
      answer = mid
      low = mid + 1
    } else {
      high = mid - 1
    }
  }

  answer
}

