def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
   val n = online.length
   val adj = Array.fill(n)(Array.empty[(Long, Long)])
   for (edge <- edges) {
      val u = edge(0)
      val v = edge(1)
      val cost = edge(2)
      if (online(v)) {
         adj(u) = adj(u) :+ (v, cost)
      }
   }

   val pq = PriorityQueue[(-Long, Long, Int)]()
   val maxMinEdge = Array.fill(n)(Long.MinValue)
   // Initialize the priority queue with edges from node 0
   for ((v, cost) <- adj(0)) {
      pq += (-cost, cost, v)
      maxMinEdge(v) = cost
   }

   while (pq.nonEmpty) {
      val (negMin, totalCost, u) = pq.dequeue()
      val currentMin = -negMin
      // Check if u is the destination
      if (u == n - 1) {
         return currentMin
      }
      // Process each outgoing edge from u
      for ((v, cost) <- adj(u)) {
         val newTotal = totalCost + cost
         if (newTotal > k) {
            // skip
         } else {
            val newMin = math.min(currentMin, cost)
            if (newMin > maxMinEdge(v)) {
               maxMinEdge(v) = newMin
               pq += (-newMin, newTotal, v)
            }
         }
      }
   }
   -1
}
